define i1 @i1_eq_corner(i1 %x, i1 %y) {
entry:
  %a = xor i1 %x, %y
  %c = icmp eq i1 %a, %x
  ret i1 %c
}

define i1 @i1_ne_corner(i1 %x, i1 %y) {
entry:
  %a = xor i1 %x, %y
  %c = icmp ne i1 %a, %x
  ret i1 %c
}

define i1 @i64_ult(i64 %x, i64 %y, i64 %z) {
entry:
  %a = xor i64 %x, %y
  %c = icmp ugt i64 %a, %z
  ret i1 %c
}

